    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M5 15v-3l6.703-6.703a1 1 0 0 1 1.414 0l1.586 1.586a1 1 0 0 1 0 1.414L8 15zm1-1v-1.586l4.354-4.353 1.585 1.585L7.586 14zm6.646-5.06 1.35-1.35-1.586-1.586-1.35 1.35z"
      fill="#3574F0"
    />
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M2 10H1V1h3.035q1.053 0 1.728.36.675.354 1 .978.324.623.324 1.416 0 .795-.324 1.408-.325.614-.996.965-.167.086-.357.15l1.383 2.516-.813.813-1.698-3.137a6 6 0 0 1-.23.004H2zm2.017-4.51H2V2h2c.485 0 .875.04 1.17.189q.444.219.645.622.202.405.202.943 0 .54-.202.93a1.33 1.33 0 0 1-.64.596q-.438.21-1.158.21"
      fill="#6C707E"
    />
  </svg>
);

const SuggestedRefactoringBulbDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M5 15v-3l6.703-6.703a1 1 0 0 1 1.414 0l1.586 1.586a1 1 0 0 1 0 1.414L8 15zm1-1v-1.586l4.354-4.353 1.585 1.585L7.586 14zm6.646-5.06 1.35-1.35-1.586-1.586-1.35 1.35z"
      fill="#548AF7"
    />
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M2 10H1V1h3.035q1.053 0 1.728.36.675.354 1 .978.324.623.324 1.416 0 .795-.324 1.408-.325.614-.996.965-.167.086-.357.15l1.383 2.516-.813.813-1.698-3.137a6 6 0 0 1-.23.004H2zm2.017-4.51H2V2h2c.485 0 .875.04 1.17.189q.444.219.645.622.202.405.202.943 0 .54-.202.93a1.33 1.33 0 0 1-.64.596q-.438.21-1.158.21"
      fill="#CED0D6"
    />
  </svg>
);

export const SuggestedRefactoringBulb: FC<SuggestedRefactoringBulbProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent =
    mode === 'light'
      ? SuggestedRefactoringBulbLight
      : SuggestedRefactoringBulbDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
